sletter_mod&id_rec=<?php  echo $id_rec; ?><?php echo $rif;?>" method="post" enctype="multipart/form-data">			<!--<div id="mws-validate-error" class="mws-form-message error" style="display:none;"></div>-->			<input type="hidden" name="stato" value="inviato">			<div class="mws-form-inline">			<?php 				$oggetto_admin->campo_mod("Data" , "data_news" , "$n_data"  , "7", 'no', "$cmd", "$id_rec");				$oggetto_admin->campo_mod("Oggetto *" , "oggetto" , "$n_titolo"  , "1", 'no', "$cmd", "$id_rec");				$oggetto_admin->campo_mod("Foto" , "img" , $n_img  , "4", 'no', $cmd, "$id_rec");			?>				<div class="mws-form-row">						<label class="mws-form-label">Testo</label>					<div class="mws-form-item">						<textarea name="testo" class="ckeditor"><?php  echo $n_testo; ?></textarea>					</div>				</div>				<div class="mws-form-row">					<label class="mws-form-label">Indirizzo email per il test</label>					<div class="mws-form-item">						<input name="email_test" type="text" class="medium" value="<?php  echo $n_email; ?>" id="email_test">					</div>				</div>			</div>			<div class="mws-button-row">				<input type="button" value="Modifica" class="btn btn-danger" onclick="verifica()">				<input type="button" value="Annulla" class="btn" onclick="annulla()">			</div>		</form>	</div></div><?php }?>